export function SettingsSectionSubtitleMessage({
  slug,
}: {
  slug: SettingsSectionSlug;
}): ReactElement | null {
  if (slug === "mcp-settings") {
    return (
      <div>
        <FormattedMessage
          id={"settings.section.mcp-settings.subtitle"}
          defaultMessage="Connect external tools and data sources. "
          description="Subtitle for MCP settings section"
        />
        <a
          className="text-token-text-secondary hover:text-token-text-primary inline-flex items-center gap-1 text-sm"
          href={CODEX_MCP_URL}
          target="_blank"
          rel="noreferrer"
        >
          <FormattedMessage
            id={"settings.section.mcp-settings.docs"}
            defaultMessage="Docs"
            description="Label for MCP docs link"
          />
          <LinkExternalIcon className="icon-xxs" />
        </a>
      </div>
    );
  }

  return null;
}
