import clsx from "clsx";
import type { HTMLAttributes, ReactElement, ReactNode } from "react";

export function SettingsContentLayout({
  title,
  backSlot,
  subtitle,
  children,
  fullWidth = false,
  contentClassName,
  action,
  className,
  ...rest
}: Omit<HTMLAttributes<HTMLDivElement>, "title"> & {
  title?: ReactNode;
  backSlot?: ReactNode;
  subtitle?: ReactNode;
  children?: ReactNode;
  fullWidth?: boolean;
  contentClassName?: string;
  action?: ReactNode;
}): ReactElement {
  return (
    <div
      className={clsx("main-surface flex h-full min-h-0 flex-col", className)}
      {...rest}
    >
      <div className="extension:h-toolbar-sm draggable electron:h-toolbar flex items-center px-panel">
        {backSlot}
      </div>
      <div className="p-panel flex-1 overflow-y-auto">
        <div
          className={clsx(
            "mx-auto flex w-full flex-col",
            fullWidth ? null : "max-w-2xl",
            contentClassName,
          )}
        >
          <div className="flex items-center justify-between gap-3 pb-panel">
            <div className="flex min-w-0 flex-1 flex-col gap-1.5 pb-panel">
              {title ? (
                <div className="electron:heading-lg heading-base truncate">
                  {title}
                </div>
              ) : null}
              {subtitle ? (
                <div className="text-base truncate text-token-text-secondary">
                  {subtitle}
                </div>
              ) : null}
            </div>
            {action ? <div className="shrink-0">{action}</div> : null}
          </div>
          <div className="flex flex-col gap-[var(--padding-panel)]">
            {children}
          </div>
        </div>
      </div>
    </div>
  );
}
