import clsx from "clsx";
import type React from "react";

/**
 * Shared container for grouping related settings rows on a secondary surface.
 */
export function SettingsSurface({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}): React.ReactElement {
  return (
    <div
      className={clsx(
        className,
        "bg-token-bg-fog border-token-border flex flex-col divide-y-[0.5px] divide-token-border rounded-lg border-[0.5px]",
      )}
    >
      {children}
    </div>
  );
}
